const ALLOWLIST = [
  'deuda-email',
  'sync-datos-automatico-ovalo',
  'nissan_postventas',
  'ovalo_conversacional_reactivo',
  'varias-vendedor',
  'nissan-vendedor',
  'AGN Hyundai wpp'
];
const BASE = 'https://puenteagenteagn.griftin.com.ar';
const workflows = $input.first().json.data || [];
const filtered = workflows.filter(wf => ALLOWLIST.includes(wf.name));
return filtered.map(wf => ({
  json: {
    workflowId: wf.id,
    workflowName: wf.name,
    workflowActive: wf.active,
    url: `${BASE}/api/v1/executions?workflowId=${wf.id}&limit=250&includeData=false`
  }
}));

const ALLOWLIST = [
  'deuda-email',
  'sync-datos-automatico-ovalo',
  'nissan_postventas',
  'ovalo_conversacional_reactivo',
  'varias-vendedor',
  'nissan-vendedor',
  'AGN Hyundai wpp'
];
const allWorkflows = $('Get Workflows').first().json.data || [];
const workflows = allWorkflows.filter(wf => ALLOWLIST.includes(wf.name));
const allExecutions = [];
$input.all().forEach(item => {
  const executions = item.json.data || [];
  allExecutions.push(...executions);
});
return [{ json: { workflows, executions: allExecutions } }];

const { workflows, executions } = $input.first().json;

const total = executions.length;
const success = executions.filter(e => e.status === 'success').length;
const failed = executions.filter(e => e.status === 'error').length;
const running = executions.filter(e => e.status === 'running').length;
const waiting = executions.filter(e => e.status === 'waiting').length;
const errorRate = total > 0 ? parseFloat(((failed / total) * 100).toFixed(2)) : 0;

const finished = executions.filter(e => e.stoppedAt && e.startedAt);
const avgDurationSeconds = finished.length > 0
  ? parseFloat((finished.reduce((acc, e) => acc + (new Date(e.stoppedAt) - new Date(e.startedAt)), 0) / finished.length / 1000).toFixed(2))
  : 0;

const byWorkflow = {};
workflows.forEach(wf => {
  byWorkflow[wf.id] = { id: wf.id, name: wf.name, active: wf.active, total: 0, success: 0, failed: 0, lastRun: null, errorRate: 0 };
});

executions.forEach(e => {
  const wfId = e.workflowId;
  if (!byWorkflow[wfId]) return;
  byWorkflow[wfId].total++;
  if (e.status === 'success') byWorkflow[wfId].success++;
  if (e.status === 'error') byWorkflow[wfId].failed++;
  if (!byWorkflow[wfId].lastRun || new Date(e.startedAt) > new Date(byWorkflow[wfId].lastRun)) {
    byWorkflow[wfId].lastRun = e.startedAt;
  }
});

const workflowStats = Object.values(byWorkflow)
  .map(wf => ({ ...wf, errorRate: wf.total > 0 ? parseFloat(((wf.failed / wf.total) * 100).toFixed(2)) : 0 }))
  .sort((a, b) => b.total - a.total);

const byDay = {};
const now = new Date();
for (let i = 6; i >= 0; i--) {
  const d = new Date(now);
  d.setDate(d.getDate() - i);
  const key = d.toISOString().split('T')[0];
  byDay[key] = { date: key, total: 0, success: 0, failed: 0 };
}
executions.forEach(e => {
  if (e.startedAt) {
    const day = e.startedAt.split('T')[0];
    if (byDay[day]) {
      byDay[day].total++;
      if (e.status === 'success') byDay[day].success++;
      if (e.status === 'error') byDay[day].failed++;
    }
  }
});

const sorted = [...executions].sort((a, b) => new Date(b.startedAt) - new Date(a.startedAt));
const lastExecution = sorted.length > 0 ? sorted[0] : null;

return [{ json: {
  generatedAt: new Date().toISOString(),
  summary: { totalExecutions: total, successExecutions: success, failedExecutions: failed, runningExecutions: running, waitingExecutions: waiting, errorRate, avgDurationSeconds },
  workflows: { total: workflows.length, active: workflows.filter(w => w.active).length, inactive: workflows.filter(w => !w.active).length },
  workflowStats,
  timeline: Object.values(byDay),
  lastExecution: lastExecution ? {
    id: lastExecution.id,
    workflowId: lastExecution.workflowId,
    status: lastExecution.status,
    startedAt: lastExecution.startedAt,
    stoppedAt: lastExecution.stoppedAt || null,
    durationSeconds: lastExecution.stoppedAt ? parseFloat(((new Date(lastExecution.stoppedAt) - new Date(lastExecution.startedAt)) / 1000).toFixed(2)) : null
  } : null
}}];

